-- ============================================================
--  Alwa Sales — 2 MORE months of sample data (days 30..89 ago)
--  Run AFTER seed_alwa_sales.sql (it reuses those products/customers
--  and continues invoice numbering). Run once in Supabase SQL Editor.
-- ============================================================
do $$
declare
  v_shop uuid; v_no int;
  p1 uuid;
  p2 uuid;
  p3 uuid;
  p4 uuid;
  p5 uuid;
  p6 uuid;
  p7 uuid;
  p8 uuid;
  p9 uuid;
  c1 uuid;
  c2 uuid;
  c3 uuid;
  c4 uuid;
begin
  select shop_id into v_shop from public.profiles pr join auth.users u on u.id=pr.id
    where u.email='alwak@alphavima.com' limit 1;   -- <-- your login email
  if v_shop is null then raise exception 'No shop found for that email'; end if;

  select id into p1 from public.products where shop_id=v_shop and name='Copper Wire 1.5mm' limit 1;
  select id into p2 from public.products where shop_id=v_shop and name='Copper Wire 2.5mm' limit 1;
  select id into p3 from public.products where shop_id=v_shop and name='Modular Switch 6A' limit 1;
  select id into p4 from public.products where shop_id=v_shop and name='LED Bulb 9W' limit 1;
  select id into p5 from public.products where shop_id=v_shop and name='MCB 16A Single Pole' limit 1;
  select id into p6 from public.products where shop_id=v_shop and name='PVC Conduit Pipe 25mm' limit 1;
  select id into p7 from public.products where shop_id=v_shop and name='Ceiling Fan 1200mm' limit 1;
  select id into p8 from public.products where shop_id=v_shop and name='Extension Board 4-way' limit 1;
  select id into p9 from public.products where shop_id=v_shop and name='Door Bell' limit 1;
  if p1 is null then raise exception 'Products not found — run seed_alwa_sales.sql first'; end if;
  select id into c1 from public.customers where shop_id=v_shop and name='Bhilai Construction Co' limit 1;
  select id into c2 from public.customers where shop_id=v_shop and name='Sharma Electricals' limit 1;
  select id into c3 from public.customers where shop_id=v_shop and name='Gupta Hardware' limit 1;
  select id into c4 from public.customers where shop_id=v_shop and name='Ramesh Kumar' limit 1;

  select next_invoice_no into v_no from public.shops where id=v_shop;



  update public.shops set next_invoice_no = v_no + 72 where id=v_shop;
  raise notice 'Loaded % more invoices (2 months)', 72;
end $$;
